content:
[workspace]
resolver = "2"
members = ["api", "core"]
exclude = ["arceos"]

[workspace.package]
version = "0.1.0"
edition = "2024"
license = "Apache-2.0"

authors = [
    "Azure-stars <Azure_stars@126.com>",
    "Yuekai Jia <equation618@gmail.com>",
    "KylinSoft Co., Ltd. <https://www.kylinos.cn/>",
    "朝倉水希 <asakuramizu111@gmail.com>",
    "Mivik <mivikq@gmail.com>",
]
homepage = "https://github.com/arceos-org/arceos"
repository = "https://github.com/arceos-org/starry-next"

[workspace.dependencies]
axfeat = { path = "arceos/api/axfeat", features = [
    "alloc-slab",
    "fp-simd",
    "fs-ext4",
    "irq",
    "multitask",
    "net",
    "page-alloc-4g",
    "rtc",
    "sched-rr",
    "task-ext",
    "uspace",
] }

axalloc = { path = "arceos/modules/axalloc" }
axconfig = { path = "arceos/modules/axconfig" }
axdisplay = { path = "arceos/modules/axdisplay" }
axdriver = { path = "arceos/modules/axdriver" }
axfs = { path = "arceos/modules/axfs" }
axhal = { path = "arceos/modules/axhal" }
axinput = { path = "arceos/modules/axinput" }
axlog = { path = "arceos/modules/axlog" }
axmm = { path = "arceos/modules/axmm" }
axnet = { path = "arceos/modules/axnet" }
axruntime = { path = "arceos/modules/axruntime" }
axsync = { path = "arceos/modules/axsync" }
axtask = { path = "arceos/modules/axtask" }

axbacktrace = "0.1"

# ==========================================================
#          2025/2026 官方初赛标准对齐 Makefile (离线编译)
# ==========================================================

# 离线编译设置
export RUSTUP_TOOLCHAIN := nightly-2025-05-20-x86_64-unknown-linux-gnu
export RUSTUP_DIST_SERVER := file:///dev/null
export RUSTUP_UPDATE_ROOT := file:///dev/null
export CARGO_NET_OFFLINE := true
export PATH := /root/.rustup/toolchains/nightly-2025-05-20-x86_64-unknown-linux-gnu/bin:$(PATH)

export LOG := warn
export DWARF := y
export BLK := y
export NET := y
export MEM := 1G
export SMP := 1

# 应用框架固有参数
export A := $(PWD)
export NO_AXSTD := y
export AX_LIB := axfeat
export APP_FEATURES := qemu

# 产物规范定义
KERNEL_RV := kernel-rv
KERNEL_LA := kernel-la
REAL_LIBCLANG_DIR ?= $(shell for d in $$(printf '%s' "$$LIBCLANG_PATH" | tr ':' ' ') /usr/lib/llvm-19/lib /usr/lib/llvm-18/lib /usr/lib/llvm-17/lib /usr/lib/llvm-16/lib /usr/lib; do if [ -n "$$d" ] && ls "$$d"/libclang.so* >/dev/null 2>&1; then echo "$$d"; break; fi; done)

# 日志中间文件名定义
LOG_RV_RAW := .build_riscv_raw.log
LOG_LA_RAW := .build_loongarch_raw.log

# 全局路径与依赖配置（保持你 reset 回来的 tools/axplat 物理路径）
LOCAL_BIN_DIR := $(PWD)/tools/axconfig-gen/bin
export PATH := $(LOCAL_BIN_DIR):/root/.cargo/bin:$(PATH)
export LIBCLANG_PATH := $(REAL_LIBCLANG_DIR)

# 显式告诉 GNU Make，当前 Makefile 中的目标不允许并行执行
.NOTPARALLEL:

# 默认总入口：评测机或本地调用 make all
all: env_bootstrap disk.img disk-la.img
	@echo "====== [STEP 1/2] 开始串行安全编译 RISC-V 64 ======"
	$(MAKE) build_riscv
	@echo "====== [STEP 2/2] 开始串行安全编译 LoongArch 64 ======"
	$(MAKE) build_loongarch

# 检查并本地编译工具链
# 🌟 爆破点 1：强行塞入 --offline，让工具链现场构建时只吃本地缓存，0秒闭环！
# 🌟 闭环强固：在工具链就绪前，物理强杀残留 QEMU 进程，彻底清洗临时缓存，打印版本快照！
env_bootstrap:
	@echo "=========================================================="
	@echo "🔍 [AUDIT] 正在核验宿主机 QEMU 物理版本快照..."
	@echo "=========================================================="
	@qemu-system-riscv64 --version 2>/dev/null || echo "⚠️ 警告：当前环境未找到 qemu-system-riscv64"
	@echo "----------------------------------------------------------"
	@qemu-system-loongarch64 --version 2>/dev/null || echo "⚠️ 警告：当前环境未找到 qemu-system-loongarch64"
	@echo "=========================================================="
	@echo "🧹 [CLEANUP] 开始无差别物理清除，强制洗净历史脏缓存..."
	@echo "=========================================================="
	@# 1. 强杀可能导致 TTY 死锁、磁盘文件独占的所有 QEMU 僵尸进程
	-@pkill -9 -f qemu-system-riscv64 2>/dev/null || true
	-@pkill -9 -f qemu-system-loongarch64 2>/dev/null || true
	-@pkill -9 -f qemu-system- 2>/dev/null || true
	@# 2. 物理洗净测试集留下的所有状态机打桩文件和编译快照
	-@rm -rf /tmp/done_* 2>/dev/null || true
	-@rm -f .build_riscv_raw.log .build_loongarch_raw.log 2>/dev/null || true
	-@rm -f workspace_*.elf workspace_*.bin 2>/dev/null || true
	@echo "=== 进程强杀与缓存清洗完成，系统归零成功！ ==="
	@echo ""
	@# 3. 判断并动态转换离线路由
	@if [ ! -d $(PWD)/.cargo ]; then \
		echo "=== 未检测到 .cargo/ 路由，开始由种子目录转换... ==="; \
		mkdir -p $(PWD)/.cargo; \
		cp $(PWD)/tools/cargo_config/config.toml $(PWD)/.cargo/config.toml; \
	fi
	@# 4. 验证本地预埋的 axconfig-gen 工具是否就绪
	@rustup default nightly-2025-05-20
	@cargo --version >/dev/null || (echo "❌ 致命错误：未能在 PATH 中找到 cargo！" && exit 1)
	@export RUSTUP_DIST_SERVER=file:///dev/null && \
	export RUSTUP_UPDATE_ROOT=file:///dev/null && \
	axconfig-gen --version
	@echo "=== 离线依赖环境物理闭环成功！ ==="

# 生成 RISC-V 评测所需的辅助磁盘镜像（对应第二个 VirtIO-MMIO 块设备驱动）
disk.img:
	@echo "正在创建 RISC-V 评测辅助镜像 disk.img (EXT4)..."
	@dd if=/dev/zero of=disk.img bs=1M count=16 >/dev/null 2>&1
	@mkfs.ext4 -F disk.img >/dev/null 2>&1

# 生成 LoongArch 评测所需的辅助磁盘镜像（对应第二个 VirtIO-PCI 块设备驱动）
disk-la.img:
	@echo "正在创建 LoongArch 评测辅助镜像 disk-la.img (EXT4)..."
	@dd if=/dev/zero of=disk-la.img bs=1M count=16 >/dev/null 2>&1
	@mkfs.ext4 -F disk-la.img >/dev/null 2>&1

# 独立编译 RISC-V 64 内核
# 🌟 爆破点 2：强行向底层注入 CARGO_ARGS="--offline"，逼迫 ArceOS 核心编译全部走本地 vendor！
build_riscv:

